Code.Terraform:
```hcl
# Terraform: 少なくとも 3 つの専用マスターノードを設定します
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  cluster_config {
    dedicated_master_enabled = true  # 重要: 専用マスターを有効にします
    dedicated_master_count   = 3     # 重要: 最低 3 つのマスターを確保します
    dedicated_master_type    = "<instance_type>"  # 重要: マスターを有効にする際に必要です
  }
}
```
